        Dua(12, "মসজিদ", "মসজিদে প্রবেশের দোয়া", "اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ", "আল্লাহুম্মাফতাহ লী আবওয়াবা রাহমাতিক", "হে আল্লাহ! আমার জন্য আপনার রহমতের দরজাগুলো খুলে দিন।", "হিসনুল মুসলিম, আবু হুমাইদ (রা.)"),
        Dua(13, "মসজিদ", "মসজিদ থেকে বের হওয়ার দোয়া", "اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ", "আল্লাহুম্মা ইন্নী আসআলুকা মিন ফাদলিক", "হে আল্লাহ! আমি আপনার অনুগ্রহ প্রার্থনা করছি।", "হিসনুল মুসলিম, আবু হুমাইদ (রা.)"),
        Dua(14, "বাড়িতে প্রবেশ", "ঘরে প্রবেশের দোয়া", "اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَ الْمَوْلِجِ وَخَيْرَ الْمَخْرَجِ بِسْمِ اللَّهِ وَلَجْنَا وَبِسْمِ اللَّهِ خَرَجْنَا وَعَلَى اللَّهِ رَبِّنَا تَوَكَّلْنَا", "আল্লাহুম্মা ইন্নী আসআলুকা খাইরাল মাওলিজি ওয়া খাইরাল মাখরাজ...", "হে আল্লাহ! আমি আপনার কাছে উত্তম প্রবেশ ও উত্তম প্রস্থানের স্থান প্রার্থনা করছি। আল্লাহর নামে প্রবেশ করছি, আল্লাহর নামে বের হচ্ছি এবং আমাদের প্রতিপালক আল্লাহর উপরই ভরসা করছি।", "হিসনুল মুসলিম, মালিক আল-আশআরী (রা.)"),
        Dua(15, "বাড়ি থেকে বের হওয়া", "ঘর থেকে বের হওয়ার দোয়া", "بِسْمِ اللَّهِ تَوَكَّلْتُ عَلَى اللَّهِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ", "বিসমিল্লাহি তাওয়াক্কালতু আলাল্লাহি লা হাওলা ওয়া লা কুওয়াতা ইল্লা বিল্লাহ", "আল্লাহর নামে বের হচ্ছি। আল্লাহর উপর ভরসা করছি। পাপ থেকে বাঁচা ও সৎকাজ করার শক্তি একমাত্র আল্লাহই দান করেন।", "হিসনুল মুসলিম, আনাস (রা.)"),
        Dua(16, "খাবার", "খাবার সামনে এলে দোয়া", "اللَّهُمَّ بَارِكْ لَنَا فِيمَا رَزَقْتَنَا وَقِنَا عَذَابَ النَّارِ", "আল্লাহুম্মা বারিক লানা ফীমা রাযাকতানা ওয়া কিনা আযাবান নার", "হে আল্লাহ! আপনি আমাদের রিযিকে বরকত দিন এবং জাহান্নামের শাস্তি থেকে রক্ষা করুন।", "প্রচলিত দোয়া"),
        Dua(17, "খাবার", "খাওয়া শুরু করার দোয়া", "بِسْمِ اللَّهِ وَعَلَى بَرَكَةِ اللَّهِ", "বিসমিল্লাহি ওয়া আলা বারাকাতিল্লাহ", "আল্লাহর নামে এবং আল্লাহর বরকতের উপর শুরু করছি।", "হিসনুল মুসলিম, আবু হুরাইরা (রা.)"),
        Dua(18, "খাবার", "বিসমিল্লাহ ভুলে গেলে দোয়া", "بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ", "বিসমিল্লাহি আওয়ালাহু ওয়া আখিরাহু", "আল্লাহর নামে, এর শুরুতে ও শেষে।", "হিসনুল মুসলিম, আয়েশা (রা.)"),
        Dua(19, "খাবার", "খাওয়া শেষ করার দোয়া", "الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مِنَ الْمُسْلِمِينَ", "আলহামদু লিল্লাহিল্লাযী আতআমানা ওয়া সাকানা ওয়া জা'আলানা মিনাল মুসলিমীন", "সমস্ত প্রশংসা আল্লাহর জন্য, যিনি আমাদের আহার করিয়েছেন, পান করিয়েছেন এবং মুসলমান বানিয়েছেন।", "হিসনুল মুসলিম, আবু সাঈদ আল-খুদরী (রা.)"),
        Dua(20, "দাওয়াত", "অন্যের ঘরে খাওয়ার পরের দোয়া", "اللَّهُمَّ أَطْعِمْ مَنْ أَطْعَمَنِي وَاسْقِ مَنْ سَقَانِي", "আল্লাহুম্মা আতইম মান আতআমানী ওয়া আসকি মান সাকানী", "হে আল্লাহ! যিনি আমাকে খাওয়ালেন ও পান করালেন, আপনি তাঁকেও খাওয়ান ও পান করান।", "হিসনুল মুসলিম"),
        Dua(21, "পানীয়", "দুধ পান করার পরের দোয়া", "اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَزِدْنَا مِنْهُ", "আল্লাহুম্মা বারিক লানা ফীহি ওয়া জিদনা মিনহু", "হে আল্লাহ! এতে আমাদের জন্য বরকত দান করুন এবং আমাদের আরও বৃদ্ধি করে দিন।", "ইবনে আব্বাস (রা.)"),
        Dua(22, "পোশাক", "কাপড় পরিধানের দোয়া", "الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ", "আলহামদু লিল্লাহিল্লাযী কাসানী হাযা ওয়া রাযাকানীহি মিন গাইরি হাওলিম মিন্নী ওয়া লা কুওয়াহ", "সমস্ত প্রশংসা আল্লাহর জন্য, যিনি আমাকে এই পোশাক পরিয়েছেন এবং আমার কোনো শক্তি বা সামর্থ্য ছাড়াই এটি দান করেছেন।", "হিসনুল মুসলিম, মু'আয ইবনে আনাস (রা.)"),
        Dua(23, "পোশাক", "নতুন কাপড় পরিধানের দোয়া", "الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي مَا أُوَارِي بِهِ عَوْرَتِي وَأَتَجَمَّلُ بِهِ فِي حَيَاتِي", "আলহামদু লিল্লাহিল্লাযী কাসানী মা উওয়ারী বিহি আওরাতী ওয়া আতাজাম্মালু বিহি ফী হায়াতী", "সমস্ত প্রশংসা আল্লাহর জন্য, যিনি আমাকে এমন পোশাক দান করেছেন যার দ্বারা আমি আমার সতর আবৃত করি এবং জীবনে সৌন্দর্য অর্জন করি।", "হিসনুল মুসলিম, উমর (রা.)"),
        Dua(24, "সফর", "সফরে বের হওয়ার দোয়া", "اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ...", "আল্লাহুম্মা আন্তাস সাহিবু ফিস সফারি ওয়াল খলিফাতু ফিল আহল...", "হে আল্লাহ! আপনি সফরে আমার সঙ্গী এবং আমার পরিবারের রক্ষণাবেক্ষণকারী। আমি সফরের কষ্ট, ফিরে আসার দুঃখ, ক্ষতি এবং পরিবারের অকল্যাণ থেকে আপনার আশ্রয় চাই।", "জামে তিরমিযী, আবদুল্লাহ ইবনে সারজিস (রা.)"),
        Dua(25, "সফর", "সফরে কোথাও অবস্থান করলে দোয়া", "أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ", "আউযু বিকালিমাতিল্লাহিত তাম্মাতি মিন শাররি মা খালাক", "আমি আল্লাহর পূর্ণাঙ্গ কালিমাসমূহের মাধ্যমে তাঁর সৃষ্ট সকল অনিষ্ট থেকে আশ্রয় প্রার্থনা করছি।", "হিসনুল মুসলিম, আবু হুরাইরা (রা.)"),
        Dua(26, "সফর", "সফর থেকে ফিরে আসার দোয়া", "آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ", "আয়িবূনা তাইবূনা আবিদূনা লিরাব্বিনা হামিদূন", "আমরা ফিরে আসছি, তাওবাকারী, ইবাদতকারী এবং আমাদের প্রতিপালকের প্রশংসাকারী।", "হিসনুল মুসলিম, আনাস (রা.)"),
        Dua(27, "বিদায়", "কাউকে বিদায় দেওয়ার দোয়া", "أَسْتَوْدِعُ اللَّهَ دِينَكَ وَأَمَانَتَكَ وَخَوَاتِيمَ عَمَلِكَ", "আস্তাওদিউল্লাহা দীনাকা ওয়া আমানাতাকা ওয়া খাওয়াতীমা আমালিক", "আমি তোমার দ্বীন, আমানত এবং শেষ আমলসমূহ আল্লাহর হেফাজতে অর্পণ করছি।", "হিসনুল মুসলিম, ইবনে উমর (রা.)"),
        Dua(28, "বিপদ", "বিপদগ্রস্ত কাউকে দেখলে দোয়া", "الْحَمْدُ لِلَّهِ الَّذِي عَافَانِي مِمَّا ابْتَلَاكَ بِهِ وَفَضَّلَنِي عَلَى كَثِيرٍ مِمَّنْ خَلَقَ تَفْضِيلًا", "আলহামদু লিল্লাহিল্লাযী আফানী মিম্মাবতালাকা বিহি ওয়া ফাদ্দালানী আলা কাসীরিম মিম্মান খালাকা তাফদীলা", "সমস্ত প্রশংসা আল্লাহর জন্য, যিনি আমাকে সেই বিপদ থেকে নিরাপদ রেখেছেন যাতে তোমাকে আক্রান্ত করেছেন এবং আমাকে তাঁর বহু সৃষ্টির উপর শ্রেষ্ঠত্ব দান করেছেন।", "হিসনুল মুসলিম, আবু হুরাইরা (রা.)"),
        Dua(29, "যানবাহন", "জন্তুর পিঠে বা বাহনে আরোহনের দোয়া", "سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ", "সুবহানাল্লাযী সাখ্খারা লানা হাযা ওয়া মা কুন্না লাহু মুকরিনীন ওয়া ইন্না ইলা রাব্বিনা লামুনকালিবূন", "পবিত্র সেই সত্তা যিনি এটিকে আমাদের অনুগত করে দিয়েছেন, অথচ আমরা নিজেরা তা নিয়ন্ত্রণ করতে সক্ষম ছিলাম না। নিশ্চয়ই আমরা আমাদের প্রতিপালকের কাছেই ফিরে যাব।", "হিসনুল মুসলিম, আলী (রা.)"),
        Dua(30, "যানবাহন", "নৌকায় আরোহনের দোয়া", "بِسْمِ اللَّهِ مَجْرَاهَا وَمُرْسَاهَا إِنَّ رَبِّي لَغَفُورٌ رَحِيمٌ", "বিসমিল্লাহি মাজরাহা ওয়া মুরসাহা ইন্না রাব্বী লাগাফুরুর রাহীম", "আল্লাহর নামেই এর চলা ও থামা। নিশ্চয়ই আমার প্রতিপালক ক্ষমাশীল ও পরম দয়ালু।", "হিসনুল মুসলিম, হুসাইন ইবনে আলী (রা.)"),
        Dua(31, "যানবাহন", "ইঞ্জিনচালিত যানবাহনে আরোহনের দোয়া", "الْحَمْدُ لِلَّهِ سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ", "আলহামদু লিল্লাহ, সুবহানাল্লাযী সাখ্খারা লানা হাযা...", "সমস্ত প্রশংসা আল্লাহর জন্য। পবিত্র সেই সত্তা যিনি এই বাহনকে আমাদের অধীন করেছেন। নিশ্চয়ই আমরা আমাদের প্রতিপালকের কাছেই ফিরে যাব।", "হিসনুল মুসলিম, আলী (রা.)"),
        Dua(32, "বাজার", "বাজারে প্রবেশের দোয়া", "لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ حَيٌّ لَا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ", "লা ইলাহা ইল্লাল্লাহু ওয়াহদাহু লা শারীকা লাহু...", "একমাত্র আল্লাহ ছাড়া কোনো উপাস্য নেই। তিনি একক, তাঁর কোনো শরীক নেই। সকল রাজত্ব ও প্রশংসা তাঁরই। তিনি জীবন ও মৃত্যু দান করেন এবং তিনি সর্বশক্তিমান।", "হিসনুল মুসলিম, উমর (রা.)"),
        Dua(33, "চাঁদ দেখা", "নতুন চাঁদ দেখার দোয়া", "اللَّهُمَّ أَهِلَّهُ عَلَيْنَا بِالْيُمْنِ وَالْإِيمَانِ وَالسَّلَامَةِ وَالْإِسْلَامِ وَالتَّوْفِيقِ لِمَا تُحِبُّ وَتَرْضَى رَبِّي وَرَبُّكَ اللَّهُ", "আল্লাহুম্মা আহিল্লাহু আলাইনা বিল ইউমনি ওয়াল ঈমান...", "হে আল্লাহ! এই চাঁদকে আমাদের জন্য নিরাপত্তা, ঈমান, শান্তি, ইসলাম এবং আপনার পছন্দনীয় কাজের তাওফিকের মাধ্যম বানিয়ে দিন।", "হিসনুল মুসলিম, তালহা ইবনে উবাইদুল্লাহ (রা.)"),
        Dua(34, "মজলিস", "মজলিসের কাফফারার দোয়া", "سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ أَشْهَدُ أَنْ لَّا إِلَهَ إِلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ", "সুবহানাকা আল্লাহুম্মা ওয়া বিহামদিকা আশহাদু আল্লা ইলাহা ইল্লা আনতা আসতাগফিরুকা ওয়া আতুবু ইলাইকা", "হে আল্লাহ! আমি আপনার পবিত্রতা ও প্রশংসা বর্ণনা করছি। আমি সাক্ষ্য দিচ্ছি যে আপনি ছাড়া কোনো উপাস্য নেই। আমি আপনার কাছে ক্ষমা চাই এবং আপনার দিকে তাওবা করি।", "হিসনুল মুসলিম, আবু হুরাইরা (রা.)"),
        Dua(35, "বিপদ", "বিপদের সময়ের দোয়া", "لَا إِلَهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَرَبُّ الْعَرْشِ الْكَرِيمِ", "লা ইলাহা ইল্লাল্লাহুল আযীমুল হালীম...", "সর্বমহান ও সহনশীল আল্লাহ ছাড়া কোনো উপাস্য নেই। মহান আরশের মালিক আল্লাহ ছাড়া কোনো উপাস্য নেই।", "হিসনুল মুসলিম, ইবনে আব্বাস (রা.)"),
        Dua(36, "ঋণ", "ঋণমুক্তির দোয়া", "اللَّهُمَّ اكْفِنِي بِحَلَالِكَ عَنْ حَرَامِكَ وَأَغْنِنِي بِفَضْلِكَ عَمَّنْ سِوَاكَ", "আল্লাহুম্মাকফিনী বিহালালিকা আন হারামিকা ওয়া আগনিনী বিফাদলিকা আম্মান সিওয়াক", "হে আল্লাহ! আপনার হালাল দ্বারা আমাকে হারাম থেকে রক্ষা করুন এবং আপনার অনুগ্রহ দ্বারা অন্যের মুখাপেক্ষী হওয়া থেকে মুক্ত রাখুন।", "হিসনুল মুসলিম, আলী (রা.)"),
        Dua(37, "শবে কদর", "শবে কদরের দোয়া", "اللَّهُمَّ إِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّي", "আল্লাহুম্মা ইন্নাকা আফুউন তুহিব্বুল আফওয়া ফা'ফু আন্নী", "হে আল্লাহ! আপনি ক্ষমাশীল, ক্ষমা করতে ভালোবাসেন। অতএব আমাকে ক্ষমা করুন।", "হিসনুল মুসলিম, আয়েশা (রা.)"),
        Dua(38, "বৃষ্টি", "বৃষ্টির সময়ের দোয়া", "اللَّهُمَّ صَيِّبًا نَافِعًا", "আল্লাহুম্মা সাইয়্যিবান নাফিআ", "হে আল্লাহ! উপকারী বৃষ্টি বর্ষণ করুন।", "হিসনুল মুসলিম, আয়েশা (রা.)"),
        Dua(39, "তুফান", "তুফানের সময়ের দোয়া", "اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا فِيهَا وَخَيْرَ مَا أُرْسِلَتْ بِهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا فِيهَا وَشَرِّ مَا أُرْسِلَتْ بِهِ", "আল্লাহুম্মা ইন্নী আসআলুকা খাইরাহা ওয়া খাইরা মা ফীহা...", "হে আল্লাহ! আমি এর কল্যাণ, এর মধ্যে থাকা কল্যাণ এবং যেই উদ্দেশ্যে এটি প্রেরিত হয়েছে তার কল্যাণ চাই। আর এর অকল্যাণ থেকে আপনার আশ্রয় চাই।", "হিসনুল মুসলিম, আয়েশা (রা.)"),
        Dua(40, "বজ্রপাত", "বজ্রের শব্দ শুনলে দোয়া", "اللَّهُمَّ لَا تَقْتُلْنَا بِغَضَبِكَ وَلَا تُهْلِكْنَا بِعَذَابِكَ وَعَافِنَا قَبْلَ ذَلِكَ", "আল্লাহুম্মা লা তাকতুলনা বিগাদাবিকা ওয়া লা তুহলিকনা বিআযাবিকা ওয়া আফিনা কাবলা যালিক", "হে আল্লাহ! আপনার ক্রোধ দ্বারা আমাদের ধ্বংস করবেন না, আপনার শাস্তি দ্বারা আমাদের বিনষ্ট করবেন না এবং এর পূর্বেই আমাদের নিরাপদ রাখুন।", "হিসনুল মুসলিম, ইবনে আব্বাস (রা.)"),
        Dua(41, "ভয়", "জালিমকে ভয় করলে দোয়া", "اللَّهُمَّ إِنَّا نَجْعَلُكَ فِي نُحُورِهِمْ وَنَعُوذُ بِكَ مِنْ شُرُورِهِمْ", "আল্লাহুম্মা ইন্না নাজআলুকা ফী নুহুরিহিম ওয়া নাঊযু বিকা মিন শুরুরিহিম", "হে আল্লাহ! আমরা তাদের মোকাবিলায় আপনার সাহায্য কামনা করি এবং তাদের অনিষ্ট থেকে আপনার আশ্রয় চাই।", "মিশকাত, আবু মূসা (রা.)"),
        Dua(42, "হাঁচি", "হাঁচি দিলে দোয়া", "الْحَمْدُ لِلَّهِ", "আলহামদু লিল্লাহ", "সমস্ত প্রশংসা আল্লাহর জন্য।", "আবু হুরাইরা (রা.)"),
        Dua(43, "হাঁচি", "হাঁচির উত্তরে দোয়া", "يَرْحَمُكَ اللَّهُ", "ইয়ারহামুকাল্লাহ", "আল্লাহ আপনার উপর রহম করুন।", "আবু হুরাইরা (রা.)"),
        Dua(44, "হাঁচি", "হাঁচিদাতার উত্তর", "يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْ", "ইয়াহদীকুমুল্লাহু ওয়া ইউসলিহু বালাকুম", "আল্লাহ আপনাদের সঠিক পথ দেখান এবং আপনাদের অবস্থা সংশোধন করুন।", "আবু হুরাইরা (রা.)"),
        Dua(45, "দোয়া", "হাস্যোজ্জ্বল মুসলমানকে দেখে দোয়া", "أَضْحَكَ اللَّهُ سِنَّكَ", "আদহাকাল্লাহু সিন্নাক", "আল্লাহ আপনাকে সর্বদা হাসিখুশি রাখুন।", "উমর (রা.)"),
        Dua(46, "মদীনা", "মদীনায় শাহাদাত ও মৃত্যুর দোয়া", "اللَّهُمَّ ارْزُقْنِي شَهَادَةً فِي سَبِيلِكَ وَاجْعَلْ مَوْتِي بِبَلَدِ رَسُولِكَ", "আল্লাহুম্মারযুকনী শাহাদাতান ফী সাবীলিকা ওয়াজআল মাওতী বিবালাদি রাসূলিক", "হে আল্লাহ! আপনার পথে শাহাদাত দান করুন এবং আপনার রাসূলের শহর মদীনায় আমার মৃত্যু দিন।", "উমর (রা.)"),
        Dua(47, "তাওবা", "গুনাহের পর ক্ষমা প্রার্থনার দোয়া", "اللَّهُمَّ مَغْفِرَتُكَ أَوْسَعُ مِنْ ذُنُوبِي وَرَحْمَتُكَ أَرْجَى عِنْدِي مِنْ عَمَلِي", "আল্লাহুম্মা মাগফিরাতুকা আওসাঊ মিন জুনুবী ওয়া রাহমাতুকা আরজা ইন্দী মিন আমালী", "হে আল্লাহ! আপনার ক্ষমা আমার গুনাহের চেয়েও ব্যাপক এবং আপনার রহমতের আশা আমার আমলের চেয়েও বেশি।", "মুনাজাতে মাকবুল"),
        Dua(48, "আয়না", "আয়নায় মুখ দেখার দোয়া", "اللَّهُمَّ حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي", "আল্লাহুম্মা হাস্সানতা খালকী ফাহাসসিন খুলুকী", "হে আল্লাহ! আপনি আমার আকৃতি সুন্দর করেছেন, অতএব আমার চরিত্রও সুন্দর করে দিন।", "ইবনে মাসউদ (রা.)"),
        Dua(49, "ওয়াসওয়াসা", "কু-ধারণা বা ওয়াসওয়াসার দোয়া", "اللَّهُمَّ لَا يَأْتِي بِالْحَسَنَاتِ إِلَّا أَنْتَ وَلَا يَذْهَبُ بِالسَّيِّئَاتِ إِلَّا أَنْتَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ", "আল্লাহুম্মা লা ইয়াতী বিল হাসানাতি ইল্লা আন্তা...", "হে আল্লাহ! আপনি ছাড়া কেউ কল্যাণ আনতে পারে আসতে পারে না এবং আপনি ছাড়া কেউ অকল্যাণ দূর করতে পারে না।", "উরওয়া ইবনে আমির (রা.)"),
        Dua(50, "রোজা", "ইফতারের দোয়া", "ذَهَبَ الظَّمَأُ وَابْتَلَّتِ الْعُرُوقُ وَثَبَتَ الْأَجْرُ إِنْ شَاءَ اللَّهُ", "যাহাবায যামাউ ওয়াবতাল্লাতিল উরূকু ওয়া সাবাতাল আজরু ইন শা আল্লাহ", "পিপাসা দূর হলো, শিরাগুলো সিক্ত হলো এবং সওয়াব সাব্যস্ত হলো, ইনশাআল্লাহ।", "ইবনে উমর (রা.)"),
        Dua(51, "প্রাণী", "মোরগের ডাক শুনলে দোয়া", "اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ", "আল্লাহুম্মা ইন্নী আসআলুকা মিন ফাদলিক", "হে আল্লাহ! আমি আপনার অনুগ্রহ প্রার্থনা করছি।", "আবু হুরাইরা (রা.)"),
        Dua(52, "প্রাণী", "গাধা বা কুকুরের ডাক শুনলে দোয়া", "أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ", "আউযু বিল্লাহি মিনাশ শাইতানির রাজীম", "আমি বিতাড়িত শয়তান থেকে আল্লাহর আশ্রয় চাই।", "আবু হুরাইরা (রা.)"),
        Dua(53, "ঈমান", "কুফরী চিন্তা এলে দোয়া", "أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ آمَنْتُ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الْآخِرِ وَالْقَدَرِ خَيْرِهِ وَشَرِّهِ مِنَ اللَّهِ تَعَالَى وَالْبَعْثِ بَعْدَ الْمَوْتِ", "আউযু বিল্লাহি মিনাশ শাইতানির রাজীম, আমানতু বিল্লাহ...", "আমি আল্লাহ, তাঁর ফেরেশতা, কিতাব, রাসূল, আখিরাত, তাকদীর এবং মৃত্যুর পর পুনরুত্থানের প্রতি ঈমান আনলাম।", "প্রচলিত দোয়া"),
        Dua(54, "ফল", "নতুন ফল খাওয়ার দোয়া", "اللَّهُمَّ بَارِكْ لَنَا فِي ثَمَرِنَا وَبَارِكْ لَنَا فِي مَدِينَتِنَا وَبَارِكْ لَنَا فِي صَاعِنَا وَبَارِكْ لَنَا فِي مُدِّنَا", "আল্লাহুম্মা বারিক লানা ফী সামারিনা...", "হে আল্লাহ! আমাদের ফল, শহর, পরিমাপ ও জীবিকায় বরকত দান করুন।", "হাদিস শরীফ"),
        Dua(55, "রোগ", "ব্যথা বা বেদনার দোয়া", "أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُ وَأُحَاذِرُ", "আউযু বিইজ্জাতিল্লাহি ওয়া কুদরাতিহি মিন শাররি মা আজিদু ওয়া উহাযির", "আমি আল্লাহর শক্তি ও ক্ষমতার মাধ্যমে বর্তমান ও আশঙ্কিত কষ্টের অনিষ্ট থেকে আশ্রয় চাই।", "উসমান ইবনে আবুল আস (রা.)"),
        Dua(56, "রোগ", "জ্বরের দোয়া", "بِسْمِ اللَّهِ الْكَبِيرِ أَعُوذُ بِاللَّهِ الْعَظِيمِ مِنْ شَرِّ كُلِّ عِرْقٍ نَعَّارٍ وَمِنْ شَرِّ حَرِّ النَّارِ", "বিসমিল্লাহিল কাবীর, আউযু বিল্লাহিল আযীম...", "আমি মহান আল্লাহর আশ্রয় চাই সকল ব্যথাদায়ক রোগ ও জাহান্নামের আগুনের অনিষ্ট থেকে।", "প্রচলিত দোয়া"),
        Dua(57, "রোগী", "রোগী দেখার দোয়া", "اللَّهُمَّ أَذْهِبِ الْبَأْسَ رَبَّ النَّاسِ اشْفِ وَأَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا", "আল্লাহুম্মা আযহিবিল বাসা রাব্বান নাস...", "হে মানুষের প্রতিপালক! রোগ দূর করুন, আরোগ্য দিন। আপনি ছাড়া প্রকৃত আরোগ্যদাতা আর কেউ নেই।", "আয়েশা (রা.)"),
        Dua(58, "চিন্তা", "দুশ্চিন্তা দূর করার দোয়া", "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْهَمِّ وَالْحُزْنِ وَأَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ وَأَعُوذُ بِكَ مِنَ الْبُخْلِ وَالْجُبْنِ وَأَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَقَهْرِ الرِّجَالِ", "আল্লাহুম্মা ইন্নী আউযুবিকা মিনাল হাম্মি ওয়াল হুযন...", "হে আল্লাহ! আমি দুশ্চিন্তা, দুঃখ, অক্ষমতা, অলসতা, কৃপণতা, ভীরুতা, ঋণের চাপ এবং মানুষের অত্যাচার থেকে আপনার আশ্রয় চাই।", "হাদিস শরীফ"),
        Dua(59, "বিবাহ", "বিবাহ বা নতুন জন্তু ক্রয়ের দোয়া", "اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا جَبَلْتَهَا عَلَيْهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا جَبَلْتَهَا عَلَيْهِ", "আল্লাহুম্মা ইন্নী আসআলুকা খাইরাহা...", "হে আল্লাহ! আমি এর কল্যাণ ও এর স্বভাবের কল্যাণ চাই এবং এর অকল্যাণ ও এর স্বভাবের অকল্যাণ থেকে আশ্রয় চাই।", "আমর ইবনুল আস (রা.)"),
        Dua(60, "পরিবার", "সহবাসের পূর্বের দোয়া", "بِسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبِ الشَّيْطَانَ مَا رَزَقْتَنَا", "বিসমিল্লাহ, আল্লাহুম্মা জান্নিবনাশ শাইতানা ওয়া জান্নিবিশ শাইতানা মা রাযাকতানা", "হে আল্লাহ! আমাদের থেকে শয়তানকে দূরে রাখুন এবং আমাদের যে সন্তান দান করবেন তার থেকেও শয়তানকে দূরে রাখুন।", "ইবনে আব্বাস (রা.)"),
        Dua(61, "ইস্তিখারা", "ইস্তিখারার দোয়া", "اللَّهُمَّ إِنِّي أَسْتَخِيْرُكَ بِعِلْمِكَ وَاسْتَقْدِرُكَ بِقُدْرَتِكَ وَاسْتَلْكَ مِنْ فَضْلِكَ الْعَظِيمِ ـ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَامُ الْغُيُوبِ...", "আল্লাহুম্মা ইন্নী আসতাখীরুকা বিইলমিকা ওয়া আসতাকদিরুকা বিকুদরাতিকা...", "হে আল্লাহ! আমি আপনার জ্ঞানের মাধ্যমে কল্যাণ কামনা করি, আপনার ক্ষমতার মাধ্যমে শক্তি চাই এবং আপনার মহান অনুগ্রহ প্রার্থনা করি। যদি এই কাজ আমার জন্য কল্যাণকর হয় তবে তা সহজ করে দিন, আর অকল্যাণকর হলে তা আমার থেকে দূরে রাখুন।", "মিশকাত শরীফ")
    )
}
